"use client";

import { Hero2 } from "./hero";

export default function Hero2Page() {
  return (
    <div className="w-full bg-background font-sans text-foreground selection:bg-primary selection:text-primary-foreground">
      <Hero2 />
    </div>
  );
}

"use client";

import {
  Check,
  Code2,
  Cpu,
  Fingerprint,
  Layers,
  Layout,
  MousePointer2,
  Palette,
  Search,
  Sparkles,
  Zap,
} from "lucide-react";
import { cn } from "@/lib/utils";

const icons = [
  { id: "layout", icon: Layout, rotate: "-10deg", y: 0, zIndex: 10 },
  { id: "zap", icon: Zap, rotate: "-8deg", y: -10, zIndex: 11 },
  { id: "palette", icon: Palette, rotate: "-6deg", y: -20, zIndex: 12 },
  { id: "search", icon: Search, rotate: "-4deg", y: -10, zIndex: 13 },
  { id: "code", icon: Code2, rotate: "-2deg", y: 0, zIndex: 14 },
  {
    id: "check",
    icon: Check,
    rotate: "0deg",
    y: 15,
    zIndex: 20,
    isCenter: true,
  },
  { id: "mouse", icon: MousePointer2, rotate: "2deg", y: 0, zIndex: 14 },
  { id: "sparkles", icon: Sparkles, rotate: "4deg", y: -10, zIndex: 13 },
  { id: "layers", icon: Layers, rotate: "6deg", y: -20, zIndex: 12 },
  { id: "cpu", icon: Cpu, rotate: "8deg", y: -10, zIndex: 11 },
  { id: "fingerprint", icon: Fingerprint, rotate: "10deg", y: 0, zIndex: 10 },
];

export function FeaturedIcons({ className }: { className?: string }) {
  return (
    <div
      className={cn(
        "mt-16 mb-24 flex items-center justify-center gap-2 sm:gap-4 lg:gap-6",
        className
      )}
    >
      {icons.map((item, _i) => (
        <div
          className={cn(
            "relative flex items-center justify-center border border-border shadow-xl transition-all duration-300",
            item.isCenter
              ? "z-20 size-24 rounded-[32px] bg-foreground text-background shadow-black/30 sm:size-28 dark:shadow-white/20"
              : "size-16 rounded-[20px] bg-card text-muted-foreground sm:size-20"
          )}
          key={item.id}
          style={{
            zIndex: item.zIndex,
            transform: `translateY(${item.y}px) rotate(${item.rotate}) ${item.isCenter ? "scale(0.9)" : ""}`,
          }}
        >
          <item.icon
            className={cn(
              item.isCenter ? "size-8 sm:size-10" : "size-5 sm:size-6"
            )}
            strokeWidth={item.isCenter ? 2.5 : 2}
          />
        </div>
      ))}
    </div>
  );
}

import React from "react";
import { cn } from "@/lib/utils";

export function BorderSeparator({
  children,
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      aria-hidden="true"
      className={cn(
        "-translate-x-1/2 pointer-events-none absolute left-1/2 w-screen border-t border-dashed",
        className
      )}
      {...props}
    >
      {children}
    </div>
  );
}

export function DashedLines({
  width = 20,
  height = 50,
  x = 10,
  className,
  ...props
}: React.ComponentProps<"svg">) {
  const id = React.useId();

  return (
    <svg
      aria-hidden="true"
      className={cn("pointer-events-none size-full stroke-border", className)}
      {...props}
    >
      <pattern
        height={height}
        id={id}
        patternUnits="userSpaceOnUse"
        width={width}
        x={x}
      >
        <path d={`M.5 0 V${height}`} fill="none" strokeDasharray={2.5} />
      </pattern>
      <rect fill={`url(#${id})`} height="100%" strokeWidth={0} width="100%" />
    </svg>
  );
}

export function GridPattern({
  width = 40,
  height = 40,
  x = -1,
  y = -1,
  strokeDasharray = "0",
  className,
  ...props
}: React.ComponentProps<"svg"> & {
  width?: number;
  height?: number;
  x?: number;
  y?: number;
  strokeDasharray?: string;
}) {
  const id = React.useId();

  return (
    <svg
      aria-hidden="true"
      className={cn(
        "pointer-events-none absolute inset-0 h-full w-full fill-transparent stroke-border/30",
        className
      )}
      {...props}
    >
      <defs>
        <pattern
          height={height}
          id={id}
          patternUnits="userSpaceOnUse"
          width={width}
          x={x}
          y={y}
        >
          <path
            d={`M.5 ${height}V.5H${width}`}
            fill="none"
            strokeDasharray={strokeDasharray}
          />
        </pattern>
      </defs>
      <rect fill={`url(#${id})`} height="100%" strokeWidth={0} width="100%" />
    </svg>
  );
}

export function GlassCard({
  children,
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div className={cn("glass-card rounded-xl p-6", className)} {...props}>
      {children}
    </div>
  );
}
